<?php declare(strict_types=1);namespace App\Services;final class StreamingProfileService{public function selectForPlaylist(array $metadata,?string $requested=null,?array $server=null,?array $health=null):array{if(!$metadata)throw new \InvalidArgumentException('Playlist metadata is required.');$c=config('profiles');$highest=$metadata[0];foreach($metadata as$m)if($m['height']>$highest['height']||($m['height']==$highest['height']&&$m['fps']>$highest['fps']))$highest=$m;$name=$requested?:$c['default'];if($name==='auto'){$name=$server['name']??'standard';if(($health['status']??'healthy')==='critical')$name='micro';if($highest['height']>1080||($highest['height']>=1080&&$highest['fps']>30))$name='standard';}$p=array_merge(['name'=>$name],$c['profiles'][$name]??$c['profiles']['standard']);$p['source_metadata']=$metadata;$p['highest_input']=$highest;return$p;}}
